import React, { useState } from 'react';
import './TopWorstSellers.css';

const TopWorstSellers = () => {
    const segments = [
        { name: 'Rum-based', value: '12.312' },
        { name: 'Whisky infused', value: '1453' },
        { name: 'Wodka-based', value: '854' },
        { name: 'Gin-based', value: '652' },
    ];

    const allItems = [
        { name: 'Bacardi cola' },
        { name: 'Gin tonic' },
        { name: 'Mojito' },
        { name: 'Whiskey sour' },
        { name: 'Espresso koffie' },
        { name: 'Bacardi cola' },
        { name: 'Gin tonic' },
        { name: 'Mojito' },
        { name: 'Whiskey sour' },
        { name: 'Espresso koffie' },
        { name: 'Bacardi cola' },
        { name: 'Bacardi cola' },
        { name: 'Gin tonic' },
        { name: 'Mojito' },
        { name: 'Whiskey sour' },
        { name: 'Espresso koffie' },
        { name: 'Bacardi cola' },
    ];

    const [searchTerm, setSearchTerm] = useState('');
    const filteredItems = allItems.filter((item) =>
        item.name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    return (
        <div className="top-worst-container">
            {/* Segment Display */}
            <div className="segment-section">
                <h2 className="section-title">Top & Worst</h2>
                <div className="segment-bars">
                    {segments.map((segment, index) => (
                        <div key={index} className="segment-bar">
                            <div className="bar-value">{segment.value}</div>
                            <button className="segment-button">{segment.name}</button>
                        </div>
                    ))}
                </div>
            </div>

            {/* Items List */}
            <div className="items-section">
                <div className="list-header">
                    <div className="header-title">
                        <p>Top & Worst</p>
                        <h2 className="section-title">Cocktail-items</h2>
                    </div>
                    <div className="section-order">
                        <span>Top sellers ↑</span>
                        <span>Worst sellers ↓</span>
                    </div>
                    {/* Search Bar */}
                    <div className="search-bar">
                        <span className="search-icon">🔍</span>
                        <input
                            type="text"
                            placeholder="Search"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                </div>
                <ul className="items-list">
                    {filteredItems.map((item, index) => (
                        <li key={index} className="item">
                            <span>{index + 1}. {item.name}</span>
                            <button className="item-button">{'>'}</button>
                        </li>
                    ))}
                </ul>
            </div>
        </div>
    );
};

export default TopWorstSellers;
